125→    public function editSpecialNicknames(Request $request): JsonResponse
126→    {
127→        $input = Arr::only($request->all(), [
128→            'type', 'nicknames_plaintext', 'sfuser_ids', 'is_on', 'special_config',
129→        ]);
130→
131→        if (!array_key_exists($input['type'], WorkflowRequestStakeholder::SPECIAL_GROUPS_MAP) || in_array($input['type'], WorkflowRequestStakeholder::P4V_TYPES)) {
132→            return $this->responseJsonFail('wrong type given', CommonException::ERR_COMMON_INVALID_ARGUMENTS);
133→        }
134→
135→        $updateColumns = [
136→            'type' => $input['type'],
137→            'creator_id' => Auth::id(),
138→            'is_on' => Arr::get($input, 'is_on', 1) === 0 ? 0 : 1, // 只有设置为 0 才表示关闭，否则都是开启状态
139→        ];
140→
141→        // 传递了 sfuser_ids, 我们才处理 nicknames, 否则我们不处理
142→        if (Arr::exists($input, 'sfuser_ids')) {
143→            $updateColumns['ids'] = Arr::get($input, 'sfuser_ids', []);
144→            $updateColumns['nicknames'] = Arr::get($input, 'nicknames_plaintext', []);
145→        }
146→
147→        // 针对特殊配置，如果传递了，需要判断部门是否重复
148→        if (Arr::has($input, 'special_config')) {
149→            $specialConfig = Arr::get($input, 'special_config');
150→            if ($specialConfig) {
151→                $departmentIds = Arr::flatten(data_get($specialConfig, '*.department_ids', []));
152→                if (count($departmentIds) != count(array_unique($departmentIds))) {
153→                    // 数目不一致，表示存在重复的部门 ID
154→                    return $this->responseJsonFail(__('my_api.repeat_department_id'), CommonException::ERR_COMMON_INVALID_ARGUMENTS);
155→                }
156→
157→                $updateColumns['special_config'] = array_map(function ($item) {
158→                    return [
159→                        'department_ids' => $item['department_ids'],
160→                        'ids' => $item['sfuser_ids'],
161→                        'nicknames' => $item['nicknames_plaintext'],
162→                    ];
163→                }, $specialConfig);
164→            } else {
165→                // 传递空的配置项的时候，将原有的置为空
166→                $updateColumns['special_config'] = [];
167→            }
168→        }
169→
170→        WorkflowSpecialStakeholder::updateOrCreate([
171→            'type' => $input['type'],
172→        ], $updateColumns);
173→
174→        // 重建 Stakeholder 的开销是很小的，并且该接口调用的可能性很小，直接更新缓存了
175→        Stakeholder::updateCache();
176→
177→        // 更新 四种 权限审批要执行人  需要变更时赋所有权限
178→        if (in_array($input['type'], WorkflowRequestStakeholder::OTHER_TYPES)) {
179→            info('四种权限审批要执行人 需要变更时赋所有权限');
180→        }
181→
182→        // 前端不需要更新后的单个数据，前端直接拉取全量数据了，这里直接返回一个 true 即可
183→        return $this->responseJsonSuccess([
184→            'success' => true,
185→        ]);
186→    }
