106→    private function processTask(object $task): void
107→    {
108→        $sfuserId = $task->sfuser_id;
109→
110→        // 读取邮箱配置
111→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
112→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
113→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no email config, skip");
114→            return;
115→        }
116→
117→        $toEmails = Arr::get($mc->config, 'to_email');
118→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
119→        if (!$sfuserToken) {
120→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no sfuser_token, skip");
121→            return;
122→        }
123→
124→        // 确定日报日期范围
125→        [$startDate, $endDate] = $this->getDateRange($task->report_range);
126→
127→        // 拉取该用户能看到日报的全部员工（维度只决定分组方式）
128→        $dailyService = app(DailyReportService::class);
129→        $subordinates = $dailyService->getSubordinates($sfuserId);
130→        // group_users 是二维数组 [groupId => [userId, ...]]，需要 flatten
131→        $groupUserIds = [];
132→        foreach ($subordinates['group_users'] as $userIds) {
133→            $groupUserIds = array_merge($groupUserIds, $userIds);
134→        }
135→        $targetUserIds = array_unique(array_merge(
136→            $subordinates['direct_subordinates'],
137→            $subordinates['depart_subordinates'],
138→            $subordinates['other_subordinates'],
139→            $subordinates['focus_users'],
140→            $groupUserIds
141→        ));
142→
143→        if (empty($targetUserIds)) {
144→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no visible users, skip");
145→            return;
146→        }
147→
148→        // 拉取日报数据
149→        $data = $dailyService->getOthersDailyReportListEnable(
150→            $startDate,
151→            $endDate,
152→            $sfuserId,
153→            $targetUserIds,
154→            10000
155→        );
156→
157→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
158→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no report data, skip");
159→            return;
160→        }
161→
162→        $reportList = $data['reports']['report_list'];
163→
164→        // 收集所有日报涉及的 sfuser_id
165→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
166→
167→        // 查询分组信息：按部门需要 department_id + department_name，按直接主管需要 direct_supervisor_id + direct_supervisor_nickname
168→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $task->dimension);
169→
170→        // 按维度分组日报
171→        $grouped = [];
172→        foreach ($reportList as $report) {
173→            $uid = $report['sfuser_id'];
174→            $groupKey = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
175→            $grouped[$groupKey]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
176→            $grouped[$groupKey]['reports'][] = $report;
177→        }
178→
179→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} dimension={$task->dimension}, groups=".count($grouped));
180→
181→        // 每个分组独立发送一封邮件，各自独立 AI 分析
182→        foreach ($grouped as $groupKey => $group) {
183→            $groupName = $group['name'];
184→            $reports = $group['reports'];
185→
186→            $dimensionLabel = $task->dimension === 'direct_manager' ? '直属主管' : '部门';
187→            $groupNameMarked = EncryptService::app()->markEncrString($groupName);
188→            // 在日报内容前加上分组上下文，解密后 AI 能识别
189→            $content = "<p><b>{$dimensionLabel}：{$groupNameMarked}</b></p>\n";
190→            $no = 0;
191→            foreach ($reports as $report) {
192→                $nickname = $report['data']['nickname'] ?? '';
193→                if (empty($nickname)) {
194→                    continue;
195→                }
196→                $nickname = EncryptService::app()->markEncrString(e($nickname));
197→                $reportContent = EncryptService::app()->markEncrString($report['content']);
198→                ++$no;
199→                $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
200→                $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
201→            }
202→
203→            if ($no === 0) {
204→                continue;
205→            }
206→
207→            $subject = "【{$startDate}】 {$task->name}（{$dimensionLabel}：{$groupNameMarked}）- 智能日报";
208→
209→            $params = [
210→                'decrypt_config' => [
211→                    'obj' => '$this',
212→                    'decrypt_columns' => [],
213→                    'partly_decrypt_columns' => ['content', 'subject'],
214→                ],
215→                'receivers' => [[
216→                    'type' => 'token',
217→                    'tokens' => [$sfuserToken],
218→                    'filter' => 'emails',
219→                    'filter_map' => ['emails' => $toEmails],
220→                ]],
221→                'content' => $content,
222→                'subject' => $subject,
223→                'ai_analysis_config' => [
224→                    'system_prompt' => $task->system_prompt,
225→                    'compress' => true,
226→                ],
227→            ];
228→
229→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} sending group={$groupName}({$no}人) to ".implode(',', $toEmails));
230→            CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
231→        }
232→
233→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} all groups sent");
234→    }
